module voltage_regulator (
    input [4:0] reg_Vin,
    output reg [4:0] Vout
);
    always @(*) begin
        if (reg_Vin < 5'd16) 
            Vout = reg_Vin;
        else if (reg_Vin < 5'd32) 
            Vout = 5'd16;
        else if (reg_Vin < 5'd48) 
            Vout = 5'd32;
        else 
            Vout = 5'd48;
    end
endmodule
